import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { CreditCard, Smartphone, Building2, Lock, CheckCircle } from 'lucide-react';
import { useCart } from '../context/CartContext';
import { toast } from 'react-toastify';
import '../assets/styles/Payment.css';

const API_BASE = 'http://localhost:5000';

// ─── Razorpay Test Credentials Info ──────────────────────────────────────────
// Key ID:     rzp_test_1DP5mmOlF5G5ag
// Test UPI:   success@razorpay  (success)  |  failure@razorpay  (failure)
// Test Card:  4111 1111 1111 1111  |  Expiry: any future  |  CVV: any 3 digits
// OTP: 1234  (for Razorpay test mode)
// GPay/PhonePe/Paytm: these will open in Razorpay's modal automatically

const UPI_APPS = [
  { id: 'gpay',    label: 'Google Pay', color: '#4285F4', emoji: '🟦' },
  { id: 'phonepe', label: 'PhonePe',    color: '#5f259f', emoji: '🟣' },
  { id: 'paytm',   label: 'Paytm',      color: '#00B9F1', emoji: '🔵' },
];

const Payment = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { cartItems, cartTotal, clearCart } = useCart();
  const addressId = location.state?.addressId;

  const [paymentTab, setPaymentTab] = useState('upi');
  const [selectedUpiApp, setSelectedUpiApp] = useState(null);
  const [upiId, setUpiId] = useState('');
  const [cardData, setCardData] = useState({ number: '', name: '', expiry: '', cvv: '' });
  const [selectedBank, setSelectedBank] = useState('SBI');
  const [processing, setProcessing] = useState(false);

  const deliveryFee = cartTotal > 500 ? 0 : 49;
  const finalTotal = cartTotal + deliveryFee;

  const getAuthHeaders = () => ({
    'Content-Type': 'application/json',
    'Authorization': `Bearer ${localStorage.getItem('token')}`
  });

  // Load Razorpay checkout script dynamically
  useEffect(() => {
    const script = document.createElement('script');
    script.src = 'https://checkout.razorpay.com/v1/checkout.js';
    script.async = true;
    document.body.appendChild(script);
    return () => document.body.removeChild(script);
  }, []);

  const openRazorpay = async (preferredMethod) => {
    if (!addressId) {
      toast.error('No delivery address selected. Please go back to checkout.');
      return;
    }

    setProcessing(true);
    try {
      // Step 1: Create Razorpay order on backend
      const res = await fetch(`${API_BASE}/api/payment/create-order`, {
        method: 'POST',
        headers: getAuthHeaders()
      });
      const data = await res.json();

      if (!data.success) {
        toast.error(data.message || 'Could not initiate payment.');
        setProcessing(false);
        return;
      }

      // Step 2: Open Razorpay checkout modal
      const options = {
        key: data.keyId,
        amount: data.amount,
        currency: data.currency,
        name: 'JaggryWeApp',
        description: 'Heritage Harvest Purchase',
        order_id: data.orderId,
        // Pre-select payment method if coming from UPI app or card button
        ...(preferredMethod && { method: preferredMethod }),
        prefill: {
          name: '',
          email: '',
          contact: ''
        },
        theme: { color: '#D4A373' },
        modal: {
          ondismiss: () => {
            toast.info('Payment cancelled. Your cart is safe.');
            setProcessing(false);
          }
        },
        handler: async (response) => {
          // Step 3: Verify payment on backend and place order
          try {
            const verifyRes = await fetch(`${API_BASE}/api/payment/verify`, {
              method: 'POST',
              headers: getAuthHeaders(),
              body: JSON.stringify({
                razorpay_order_id: response.razorpay_order_id,
                razorpay_payment_id: response.razorpay_payment_id,
                razorpay_signature: response.razorpay_signature,
                addressId
              })
            });
            const verifyData = await verifyRes.json();
            if (verifyData.success) {
              await clearCart();
              navigate('/order-success', { state: { order: verifyData.order } });
            } else {
              toast.error(verifyData.message);
              setProcessing(false);
            }
          } catch (err) {
            toast.error('Order placement failed after payment. Contact support.');
            setProcessing(false);
          }
        }
      };

      if (!window.Razorpay) {
        toast.error('Razorpay SDK failed to load. Check your internet connection.');
        setProcessing(false);
        return;
      }

      const rzpInstance = new window.Razorpay(options);
      rzpInstance.on('payment.failed', (response) => {
        toast.error(`Payment failed: ${response.error.description}`);
        setProcessing(false);
      });
      rzpInstance.open();

    } catch (err) {
      toast.error('Something went wrong. Please try again.');
      setProcessing(false);
    }
  };

  const handlePay = () => {
    if (paymentTab === 'upi') {
      if (!selectedUpiApp && !upiId.includes('@')) {
        toast.error('Please select a UPI app or enter a valid UPI ID (e.g. success@razorpay)');
        return;
      }
      openRazorpay({ flow: 'intent', upi_app: selectedUpiApp || undefined });
    } else if (paymentTab === 'card') {
      if (!cardData.number || !cardData.name || !cardData.expiry || !cardData.cvv) {
        toast.error('Please fill all card details.');
        return;
      }
      openRazorpay('card');
    } else {
      openRazorpay('netbanking');
    }
  };

  return (
    <div className="payment-page">
      <div className="payment-container">

        {/* Test Credentials Banner */}
        <div className="test-credentials-banner">
          <strong>🧪 Test Mode Active</strong>
          <span>UPI: <code>success@razorpay</code></span>
          <span>Card: <code>4111 1111 1111 1111</code> · Any expiry · Any CVV · OTP: <code>1234</code></span>
        </div>

        <div className="payment-grid">
          {/* Left: Payment Methods */}
          <div className="payment-methods-panel">
            <div className="payment-header">
              <Lock size={16} />
              <h2>Secure Payment</h2>
            </div>

            {/* Tabs */}
            <div className="payment-tabs">
              <button type="button" className={`pay-tab ${paymentTab === 'upi' ? 'active' : ''}`} onClick={() => setPaymentTab('upi')}>
                <Smartphone size={16} /> UPI
              </button>
              <button type="button" className={`pay-tab ${paymentTab === 'card' ? 'active' : ''}`} onClick={() => setPaymentTab('card')}>
                <CreditCard size={16} /> Card
              </button>
              <button type="button" className={`pay-tab ${paymentTab === 'netbanking' ? 'active' : ''}`} onClick={() => setPaymentTab('netbanking')}>
                <Building2 size={16} /> Net Banking
              </button>
            </div>

            {/* UPI Panel */}
            {paymentTab === 'upi' && (
              <div className="pay-form">
                <h3>Pay via UPI</h3>
                <p className="pay-hint">Select an app or enter your UPI ID</p>

                <div className="upi-apps">
                  {UPI_APPS.map(app => (
                    <button
                      key={app.id}
                      type="button"
                      className={`upi-app-btn ${selectedUpiApp === app.id ? 'selected' : ''}`}
                      onClick={() => { setSelectedUpiApp(app.id); setUpiId(''); }}
                    >
                      <span className="upi-emoji">{app.emoji}</span>
                      <span>{app.label}</span>
                      {selectedUpiApp === app.id && <CheckCircle size={14} className="upi-check" />}
                    </button>
                  ))}
                </div>

                <div className="pay-divider"><span>or enter UPI ID manually</span></div>

                <label>UPI ID</label>
                <input
                  type="text"
                  placeholder="yourname@upi  (test: success@razorpay)"
                  value={upiId}
                  onChange={e => { setUpiId(e.target.value); setSelectedUpiApp(null); }}
                />
              </div>
            )}

            {/* Card Panel */}
            {paymentTab === 'card' && (
              <div className="pay-form">
                <h3>Pay via Debit / Credit Card</h3>
                <p className="pay-hint">Test: 4111 1111 1111 1111 · Any expiry · Any CVV · OTP: 1234</p>
                <label>Card Number</label>
                <input type="text" placeholder="4111 1111 1111 1111" maxLength={19}
                  value={cardData.number} onChange={e => setCardData({...cardData, number: e.target.value})} />
                <label>Cardholder Name</label>
                <input type="text" placeholder="Name on card"
                  value={cardData.name} onChange={e => setCardData({...cardData, name: e.target.value})} />
                <div className="card-row">
                  <div>
                    <label>Expiry</label>
                    <input type="text" placeholder="MM/YY" maxLength={5}
                      value={cardData.expiry} onChange={e => setCardData({...cardData, expiry: e.target.value})} />
                  </div>
                  <div>
                    <label>CVV</label>
                    <input type="password" placeholder="•••" maxLength={3}
                      value={cardData.cvv} onChange={e => setCardData({...cardData, cvv: e.target.value})} />
                  </div>
                </div>
              </div>
            )}

            {/* Net Banking Panel */}
            {paymentTab === 'netbanking' && (
              <div className="pay-form">
                <h3>Net Banking</h3>
                <p className="pay-hint">You will be redirected to your bank's portal</p>
                <label>Select your bank</label>
                <select value={selectedBank} onChange={e => setSelectedBank(e.target.value)}>
                  <option value="SBI">State Bank of India</option>
                  <option value="HDFC">HDFC Bank</option>
                  <option value="ICICI">ICICI Bank</option>
                  <option value="AXIS">Axis Bank</option>
                  <option value="KOTAK">Kotak Mahindra</option>
                </select>
              </div>
            )}
          </div>

          {/* Right: Order Summary */}
          <div className="payment-summary-panel">
            <h3>Order Summary</h3>
            <div className="pay-summary-items">
              {cartItems.map(item => (
                <div key={item.itemId} className="pay-summary-row">
                  <span>{item.title} × {item.quantity}</span>
                  <span>₹{(item.price * item.quantity).toFixed(2)}</span>
                </div>
              ))}
            </div>
            <div className="pay-total-rows">
              <div className="pay-total-row"><span>Subtotal</span><span>₹{cartTotal.toFixed(2)}</span></div>
              <div className="pay-total-row"><span>Delivery</span><span>{deliveryFee === 0 ? '🎉 FREE' : `₹${deliveryFee}`}</span></div>
              <div className="pay-total-row grand"><span>Total</span><span>₹{finalTotal.toFixed(2)}</span></div>
            </div>

            <button
              type="button"
              className="pay-now-btn"
              onClick={handlePay}
              disabled={processing}
            >
              {processing ? (
                <span className="paying-spinner">
                  <span className="spinner-dot"></span> Opening Razorpay...
                </span>
              ) : (
                `Pay ₹${finalTotal.toFixed(2)} via ${paymentTab === 'upi' ? 'UPI' : paymentTab === 'card' ? 'Card' : 'Net Banking'}`
              )}
            </button>
            <p className="secure-note"><Lock size={12} /> 256-bit SSL Encrypted · Powered by Razorpay</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Payment;
